sql:
SELECT name
FROM dbms_models
WHERE is_active = 1;

external_knowledge:
- In the context of DBMS, "major version" typically refers to significant releases that introduce substantial changes, features, or improvements; 
- "Cumulative rank" implies a sum of ranks over time, showing a DBMS's performance trend; 
- "Final rank" refers to the latest rank available for each DBMS; 
- "Rank position" signifies the position a DBMS holds within its final rank, indicating its relative market standing.

sql:
SELECT rank
FROM dbms_rankings
WHERE year = 2022 AND quarter = 'Q4' AND source = 'Gartner';

SELECT role_id, last_updated
FROM user_role_mappings
WHERE user_id = 1;

SELECT dbms_id, MAX(rank) AS highest_rank
FROM dbms_rankings
GROUP BY dbms_id;

SELECT COUNT(*) 
FROM dbms_releases 
WHERE is_major_release = 1;

SELECT d.name
FROM dbms d
JOIN dbms_rankings r ON d.dbms_id = r.dbms_id
WHERE r.year = (
    SELECT MAX(year) FROM dbms_rankings
) AND r.quarter = (
    SELECT MAX(quarter) FROM dbms_rankings WHERE year = (
        SELECT MAX(year) FROM dbms_rankings
    )
)
ORDER BY r.rank DESC
LIMIT 1;

SELECT COUNT(*) AS active_dbms_model_count
FROM dbms_models
WHERE is_active = 1;

SELECT COUNT(*) as open_source_dbms_count
FROM dbms
WHERE license = 'open source';

SELECT name, description
FROM dbms_models
WHERE is_active = 1;
